  "main.rs": "use std::ptr;

const BYTES_PER_PIXEL: usize = 4;

/// Flip a single line of 4-byte pixels in-place.
///
/// Works for any `line_bytes.len()` that is a multiple of 4.
/// Uses `u32` swaps when the buffer is 4-byte aligned, otherwise falls back
/// to swapping 4 bytes at a time.
fn flip_line(line_bytes: &mut [u8]) {
    assert!(line_bytes.len() % BYTES_PER_PIXEL == 0);

    let pixels = line_bytes.len() / BYTES_PER_PIXEL;
    if pixels <= 1 {
        return;
    }

    let base = line_bytes.as_mut_ptr();

    // Fast path: swap pixels as u32 when 4-byte aligned.
    if (base as usize) % std::mem::align_of::<u32>() == 0 {
        let p32 = base.cast::<u32>();
        for i in 0..(pixels / 2) {
            unsafe {
                ptr::swap_nonoverlapping(p32.add(i), p32.add(pixels - 1 - i), 1);
            }
        }
    } else {
        // Fallback: swap each pixel as 4 bytes.
        for i in 0..(pixels / 2) {
            let left = i * BYTES_PER_PIXEL;
            let right = (pixels - 1 - i) * BYTES_PER_PIXEL;
            unsafe {
                ptr::swap_nonoverlapping(base.add(left), base.add(right), BYTES_PER_PIXEL);
            }
        }
    }
}

