",
  "main.rs": "use std::io::{self, Read};

#[derive(Debug, Clone, PartialEq, Eq)]
pub enum TokenizeError {
    UnclosedSingleQuote,
}

/// Tokenize like a very small subset of bash:
/// - splits on (space | tab | newline) when not inside single quotes
/// - single quotes preserve all characters verbatim and are removed
/// - quoted and unquoted parts can be adjacent and are concatenated into one token
/// - supports empty arguments via ''
pub fn tokenize(input: &str) -> Result<Vec<String>, TokenizeError> {
    let mut tokens = Vec::new();
    let mut cur = String::new();

    let mut in_single_quote = false;
    // Whether we have started an argument (even if `cur` is empty), e.g. via "''".
    let mut token_started = false;

    for ch in input.chars() {
        if in_single_quote {
            if ch == '\'' {
                in_single_quote = false;
            } else {
                cur.push(ch);
                token_started = true;
            }
            continue;
        }

        match ch {
            '\'' => {
                in_single_quote = true;
                token_started = true; // allows empty arg: ''
            }
            ' ' | '\t' | '\n' => {
                if token_started {
                    tokens.push(std::mem::take(&mut cur));
                    token_started = false;
                }
            }
            _ => {
                cur.push(ch);
                token_started = true;
            }
        }
    }

    if in_single_quote {
        return Err(TokenizeError::UnclosedSingleQuote);
    }

    if token_started {
        tokens.push(cur);
    }

    Ok(tokens)
}

fn main() {
    // If stdin has content, tokenize that; otherwise, show the example.
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf).ok();

    let input = if buf.trim_end().is_empty() {
        " one  ' two  'three    four"
    } else {
        // Only tokenize the first line, similar to a shell reading a command line.
        buf.lines().next().unwrap_or("")
    };

    match tokenize(input) {
        Ok(args) => {
            println!("{} args:", args.len());
            for a in args {
                println!("<{}>", a);
            }
        }
        Err(e) => {
            eprintln!("tokenize error: {e:?}");
            std::process::exit(2);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn matches_prompt_example() {
        let s = " one  ' two  'three    four";
        let got = tokenize(s).unwrap();
        assert_eq!(got, vec!["one", " two  three", "four"]);
    }

    #[test]
    fn empty_arg() {
        let s = "a '' b";
        let got = tokenize(s).unwrap();
        assert_eq!(got, vec!["a", "", "b"]);
