impl<T> Array<T> {
    pub fn from_fn(dims: Vec<usize>, mut f: impl FnMut(usize) -> T) -> Self {
        assert!(!dims.is_empty());
        let len = dims.iter().product();
        let mut store = Vec::with_capacity(len);
        for i in 0..len {
            store.push(f(i));
        }
        Self { store, dims }
    }

    pub fn dims(&self) -> &[usize] {
        &self.dims
    }

    pub fn len(&self) -> usize {
        self.store.len()
    }

    fn linear_index(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len());
        let mut lin = 0usize;
        let mut stride = 1usize;
        for (&i, &d) in idx.iter().rev().zip(self.dims.iter().rev()) {
            assert!(i < d);
            lin += i * stride;
            stride *= d;
        }
        lin
    }

    fn cartesian_index(&self, mut lin: usize) -> Vec<usize> {
        assert!(lin < self.len());
        let mut idx = vec![0usize; self.dims.len()];
        for (k, &d) in self.dims.iter().rev().enumerate() {
            let axis = self.dims.len() - 1 - k;
            idx[axis] = lin % d;
            lin /= d;
        }
        idx
    }

    pub fn iter(&self) -> ArrayIter<'_, T> {
        ArrayIter {
            array: self,
            next_lin: 0,
        }
    }

    pub fn iter_mut(&mut self) -> ArrayIterMut<'_, T> {
        // IMPORTANT: we borrow `self` for the iterator's lifetime, so callers cannot
        // access the array while the iterator exists.
        // Internally, we use a raw pointer so `next()` can yield `&'a mut T`.
        ArrayIterMut {
            ptr: self.store.as_mut_ptr(),
            dims: self.dims.clone(),
            len: self.store.len(),
            next_lin: 0,
            _marker: PhantomData,
        }
    }
}

impl<T> Index<&[usize]> for Array<T> {
    type Output = T;

    fn index(&self, idx: &[usize]) -> &Self::Output {
        let lin = self.linear_index(idx);
        &self.store[lin]
    }
}

impl<T> IndexMut<&[usize]> for Array<T> {
    fn index_mut(&mut self, idx: &[usize]) -> &mut Self::Output {
        let lin = self.linear_index(idx);
        &mut self.store[lin]
    }
}

#[derive(Debug)]
pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    next_lin: usize,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.next_lin >= self.array.len() {
            return None;
        }
        let lin = self.next_lin;
        self.next_lin += 1;

        let idx = self.array.cartesian_index(lin);
        let r = &self.array.store[lin];
        Some((idx, r))
    }
}

#[derive(Debug)]
pub struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    dims: Vec<usize>,
    len: usize,
    next_lin: usize,
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> ArrayIterMut<'a, T> {
    fn cartesian_index(&self, mut lin: usize) -> Vec<usize> {
        assert!(lin < self.len);
        let mut idx = vec![0usize; self.dims.len()];
        for (k, &d) in self.dims.iter().rev().enumerate() {
            let axis = self.dims.len() - 1 - k;
            idx[axis] = lin % d;
            lin /= d;
        }
        idx
    }
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.next_lin >= self.len {
            return None;
        }
        let lin = self.next_lin;
        self.next_lin += 1;

        let idx = self.cartesian_index(lin);

        // SAFETY:
        // - `ptr` points to the backing allocation of the original `Array<T>`.
        // - We advance `lin` monotonically and never repeat it, so we never create
        //   two `&mut` aliases to the same element.
        // - The iterator is created from `&'a mut Array<T>`, so the array cannot be
        //   accessed concurrently while the iterator exists.
        let r: &'a mut T = unsafe { &mut *self.ptr.add(lin) };
        Some((idx, r))
    }
}

