  "main.rs": "use critical_section::with;
use std::sync::{atomic::AtomicUsize, atomic::Ordering, Arc, Mutex};
use std::thread;

/// A counter that emulates `fetch_add` using a critical section.
///
/// Notes about memory ordering:
/// - Your original code used `fetch_add(1, Ordering::Relaxed)`.
/// - If all accesses to the counter are performed *inside the same critical section*,
///   then the atomic *ordering* on the load/store is effectively irrelevant for
///   correctness of the counter itself, because the critical section provides
///   mutual exclusion (atomicity).
/// - To preserve the intent and cost of the original `Relaxed` increment, use
///   `Relaxed` for the internal load/store too.
/// - If you needed synchronization with *other data* (not just uniqueness of the
///   returned index), you would normally rely on the critical-section mechanism
///   itself (it should behave like a lock with acquire/release semantics on real
///   targets) rather than cranking the atomic orderings up to `SeqCst`.
///
/// Important: This is only correct if *every* access to `channel_index` uses the
/// same critical-section protection. Mixing CS-protected access with plain atomic
/// operations on another core/interrupt would reintroduce races.
struct Counter {
    channel_index: AtomicUsize,
}

impl Counter {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replacement for `fetch_add(1, Ordering::Relaxed)`.
    fn fetch_add_relaxed_via_cs(&self) -> usize {
        with(|_| {
            // `Relaxed` matches the original intent: no ordering guarantees beyond
            // producing a unique number.
            let old = self.channel_index.load(Ordering::Relaxed);
            self.channel_index.store(old.wrapping_add(1), Ordering::Relaxed);
            old
        })
    }

    fn load_relaxed(&self) -> usize {
        self.channel_index.load(Ordering::Relaxed)
    }
}

fn main() {
    let counter = Arc::new(Counter::new());

    let threads = 8usize;
    let iters = 50_000usize;

    // Collect returned indices to sanity-check uniqueness.
    let results: Arc<Mutex<Vec<usize>>> = Arc::new(Mutex::new(Vec::with_capacity(threads * iters)));

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = Arc::clone(&counter);
        let r = Arc::clone(&results);
        handles.push(thread::spawn(move || {
            for _ in 0..iters {
                let idx = c.fetch_add_relaxed_via_cs();
                r.lock().unwrap().push(idx);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let expected = threads * iters;
    let final_val = counter.load_relaxed();
    assert_eq!(final_val, expected, "final counter value should match total increments");

    // Verify returned indices cover [0, expected) without duplicates.
    let mut v = Arc::try_unwrap(results).unwrap().into_inner().unwrap();
    v.sort_unstable();
    assert_eq!(v.len(), expected);
    for (i, got) in v.into_iter().enumerate() {
        assert_eq!(got, i, "index sequence should be contiguous and unique");
    }

    println!("OK: got {expected} unique indices; final counter = {final_val}");
}
