name = "lancedb_datetime_parse_demo"
version = "0.1.0"
edition = "2021"

[dependencies]
chrono = { version = "0.4", default-features = false, features = ["clock"] }
",
  "main.rs": "use chrono::{DateTime, NaiveDateTime, Utc};

fn parse_lance_datetime(input: &str) -> Result<DateTime<Utc>, String> {
    // Lance/Arrow sometimes returns quoted strings depending on how you print them.
    let mut s = input.trim().trim_matches('"').to_string();

    // Handle the "trailing decimal" case, e.g. "2025-08-02T17:35:41." -> treat as .0
    if s.ends_with('.') {
        s.push('0');
    }

    // 1) If the string already has a timezone (RFC3339), parse it directly.
    //    Examples: 2025-08-02T17:35:41.409Z or 2025-08-02T17:35:41+00:00
    if let Ok(dt) = DateTime::parse_from_rfc3339(&s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // 2) Otherwise, Lance often formats timestamps without a timezone.
    //    Parse as a NaiveDateTime and assume UTC.
    let formats = [
        // with fractional seconds (1-9 digits)
        "%Y-%m-%dT%H:%M:%S%.f",
        // without fractional seconds
        "%Y-%m-%dT%H:%M:%S",
    ];

    for fmt in formats {
        if let Ok(ndt) = NaiveDateTime::parse_from_str(&s, fmt) {
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(ndt, Utc));
        }
    }

    Err(format!(
        "Could not parse datetime from: {input:?} (normalized: {s:?})"
    ))
}

fn datetime_to_unix_millis(dt: DateTime<Utc>) -> i64 {
    dt.timestamp_millis()
}

fn main() {
    let samples = [
        "1970-01-01T00:00:00",
        "2025-08-02T17:35:41.409",
        "2025-08-04T01:48:44.017",
        "2025-08-04T23:02:20.584",
        "2025-08-05T00:08:57.350",
        "2025-08-10T18:31:26.628",
        // a few extra cases you might encounter:
        "2025-08-02T17:35:41.",
        "2025-08-02T17:35:41Z",
        "2025-08-02T17:35:41.409Z",
        "2025-08-02T17:35:41+00:00",
    ];

    for s in samples {
        match parse_lance_datetime(s) {
            Ok(dt) => {
                let ms = datetime_to_unix_millis(dt);
                println!("Input: {s:?}");
                println!("  Parsed (UTC): {dt}");
                println!("  unix_ms: {ms}");
            }
            Err(e) => {
                println!("Input: {s:?}");
                println!("  ERROR: {e}");
            }
        }
    }
}
"
}
