{
  "Cargo.toml": "[package]
name = "dogstatsd_unix_test"
version = "0.1.0"
edition = "2021"

[dependencies]
anyhow = "1.0"
clap = { version = "4.5", features = ["derive"] }
# If you don't need unix sockets, you can remove the `unix` feature.
cadence = { version = "0.29", features = ["unix"] }
",
  "main.rs": "use anyhow::{anyhow, Context, Result};
use cadence::{
    BufferedUnixMetricSink, BufferedUdpMetricSink, Counted, MetricError, QueuingMetricSink,
    StatsdClient, UdpMetricSink,
};
use clap::{Parser, ValueEnum};
use std::net::UdpSocket;
use std::sync::{Arc, Mutex};
use std::thread;
use std::time::{Duration, Instant};

#[derive(Debug, Clone, ValueEnum)]
enum Mode {
    Unix,
    Udp,
}

#[derive(Debug, Parser)]
#[command(author, version, about)]
struct Args {
    /// Transport mode: unix socket (DogStatsD socket) or UDP.
    #[arg(long, value_enum, default_value_t = Mode::Unix)]
    mode: Mode,

    /// Unix socket path (when --mode unix)
    #[arg(long, default_value = "/var/run/datadog/dsd.socket")]
    socket_path: String,

    /// UDP host (when --mode udp)
    #[arg(long, default_value = "127.0.0.1")]
    udp_host: String,

    /// UDP port (when --mode udp)
    #[arg(long, default_value_t = 8125)]
    udp_port: u16,

    /// StatsD metric prefix
    #[arg(long, default_value = "rusttest")]
    prefix: String,

    /// Metric name (without prefix)
    #[arg(long, default_value = "operations.count")]
    metric: String,

    /// Tags in the form key=value. Repeatable.
    #[arg(long = "tag", value_parser = parse_tag)]
    tags: Vec<(String, String)>,

    /// Send this many metrics per second total (across all threads).
    #[arg(long, default_value_t = 1000)]
    rate: u64,

    /// Run for this many seconds.
    #[arg(long, default_value_t = 20)]
    duration_secs: u64,

    /// Number of sending threads.
    #[arg(long, default_value_t = 1)]
    threads: usize,

    /// If set, add a high-cardinality tag (seq=<n>) that changes every metric.
    /// Useful to see if you're hitting tag/cardinality limits.
    #[arg(long, default_value_t = false)]
    unique_tag_per_metric: bool,

    /// If set, prints every send error (can be noisy at high rate).
    #[arg(long, default_value_t = false)]
    verbose_errors: bool,
}

fn parse_tag(s: &str) -> Result<(String, String), String> {
    let (k, v) = s
        .split_once('=')
        .ok_or_else(|| "tag must be in key=value form".to_string())?;
    if k.is_empty() {
        return Err("tag key must not be empty".to_string());
    }
    Ok((k.to_string(), v.to_string()))
}

fn main() -> Result<()> {
    let args = Args::parse();

    if args.threads == 0 {
        return Err(anyhow!("--threads must be >= 1"));
    }

    let client = create_statsd_client(&args)?;

    let rate_per_thread = std::cmp::max(1, args.rate / args.threads as u64);
    let duration = Duration::from_secs(args.duration_secs);

    eprintln!(
        "Sending {} metrics/sec total for {:?} using {:?} (threads={}, per-thread rate={}/sec)",
        args.rate, duration, args.mode, args.threads, rate_per_thread
    );

    let totals = Arc::new(Mutex::new((0u64, 0u64))); // (sent_ok, send_err)
    let start = Instant::now();
    let end = start + duration;

    let mut handles = Vec::with_capacity(args.threads);
    for t in 0..args.threads {
        let client = Arc::clone(&client);
        let metric = args.metric.clone();
        let tags = args.tags.clone();
        let totals = Arc::clone(&totals);
        let verbose_errors = args.verbose_errors;
        let unique = args.unique_tag_per_metric;
        let thread_end = end;

        handles.push(thread::spawn(move || {
            let mut seq: u64 = (t as u64) * 1_000_000_000;

            while Instant::now() < thread_end {
                let tick_start = Instant::now();

                let mut ok = 0u64;
                let mut err = 0u64;

                for _ in 0..rate_per_thread {
                    let mut builder = client.incr_with_tags(&metric);
                    for (k, v) in &tags {
                        builder = builder.with_tag(k, v);
                    }
                    if unique {
                        builder = builder.with_tag("seq", seq.to_string());
                        seq += 1;
                    }

                    match builder.try_send() {
                        Ok(()) => ok += 1,
                        Err(e) => {
                            err += 1;
                            if verbose_errors {
                                eprintln!("send error: {e:?}");
                            }
                        }
                    }
                }

                // Update totals.
                {
                    let mut g = totals.lock().unwrap();
                    g.0 += ok;
                    g.1 += err;
                }

                // Try to roughly pace to 1-second ticks.
                let elapsed = tick_start.elapsed();
                if elapsed < Duration::from_secs(1) {
                    thread::sleep(Duration::from_secs(1) - elapsed);
                }
            }
        }));
    }

    // Progress reporter.
    while Instant::now() < end {
        thread::sleep(Duration::from_secs(1));
        let (ok, err) = *totals.lock().unwrap();
        eprintln!("progress: ok_sent={} err_sent={}", ok, err);
    }

    for h in handles {
        let _ = h.join();
    }

    let (ok, err) = *totals.lock().unwrap();
    eprintln!("done: ok_sent={} err_sent={}", ok, err);

    Ok(())
}

fn create_statsd_client(args: &Args) -> Result<Arc<StatsdClient>> {
    let error_handler = |e: MetricError| {
        eprintln!("[cadence error] {e:?}");
    };

    let client = match args.mode {
        Mode::Unix => {
            #[cfg(not(unix))]
            {
                return Err(anyhow!("unix mode requires a unix-like OS"));
            }

            #[cfg(unix)]
            {
                use std::os::unix::net::UnixDatagram;

                let sock = UnixDatagram::unbound().context("failed to create unix datagram")?;
                sock.connect(&args.socket_path)
                    .with_context(|| format!("failed to connect to socket: {}", args.socket_path))?;

                // BufferedUnixMetricSink takes (path, socket) in cadence 0.29.
                let sink = BufferedUnixMetricSink::from(args.socket_path.clone(), sock);
                let sink = QueuingMetricSink::from(sink);

                StatsdClient::builder(args.prefix.clone(), sink)
                    .with_error_handler(error_handler)
                    .build()
            }
        }
        Mode::Udp => {
            let bind = "0.0.0.0:0";
            let udp = UdpSocket::bind(bind).with_context(|| format!("udp bind failed: {bind}"))?;
            let host = (args.udp_host.as_str(), args.udp_port);
            let sink = UdpMetricSink::from(host, udp)
                .with_context(|| format!("failed to create udp sink to {:?}", host))?;
            let sink = BufferedUdpMetricSink::from(sink);
            let sink = QueuingMetricSink::from(sink);

            StatsdClient::builder(args.prefix.clone(), sink)
                .with_error_handler(error_handler)
                .build()
        }
    };

    Ok(Arc::new(client))
}
"
}

