#[derive(Clone)]
struct RequestCtx {
    // This is the key: store the *tracing* span for the request.
    // `tracing::Span` is cheap to clone and can be entered on any thread.
    request_span: tracing::Span,
}

fn init_tracing() {
    // Export OTEL spans to stdout so you can see the parent/child relationships.
    let exporter = opentelemetry_stdout::SpanExporter::default();

    let provider = sdktrace::TracerProvider::builder()
        .with_simple_exporter(exporter)
        .with_config(
            sdktrace::Config::default().with_resource(Resource::new(vec![KeyValue::new(
                "service.name",
                "rehydrate-span-demo",
            )])),
        )
        .build();

    let tracer = provider.tracer("demo-tracer");
    opentelemetry::global::set_tracer_provider(provider);

    let otel_layer = OpenTelemetryLayer::new(tracer);

    // Also print tracing logs with span enter/exit to stdout.
    tracing_subscriber::registry()
        .with(
            EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| EnvFilter::new("info")),
        )
        .with(
            tracing_subscriber::fmt::layer()
                .with_target(false)
                .with_thread_ids(true)
                .with_thread_names(true)
                .with_span_events(tracing_subscriber::fmt::format::FmtSpan::ENTER
                    | tracing_subscriber::fmt::format::FmtSpan::EXIT),
        )
        .with(otel_layer)
        .init();
}

// Simulates a Pingora/Tokio callback that can happen later/on any worker thread.
async fn stage_1(ctx: Arc<RequestCtx>) {
    // Rehydrate the request span as the *current* span for this callback.
    // Anything created inside (without explicit parent) becomes a child.
    let _req_guard = ctx.request_span.enter();

    let stage_span = info_span!("stage_1");
    let _stage_guard = stage_span.enter();

    info!("doing stage 1 work");
    tokio::time::sleep(Duration::from_millis(80)).await;
    info!("stage 1 done");
}

// Another callback, but demonstrates the async-friendly way: instrument the future.
async fn stage_2(ctx: Arc<RequestCtx>) {
    // Here we assume the caller already instrumented the future with request_span,
    // so `info_span!("stage_2")` automatically becomes a child of the request.
    let stage_span = info_span!("stage_2");
    async move {
        info!("doing stage 2 work");

        // Nested span (child of stage_2).
        let upstream = info_span!("upstream");
        async {
            info!("calling upstream");
            tokio::time::sleep(Duration::from_millis(50)).await;
            info!("upstream done");
        }
        .instrument(upstream)
        .await;

        info!("stage 2 done");
    }
    .instrument(stage_span)
    .await;
}

#[tokio::main(flavor = "multi_thread", worker_threads = 2)]
async fn main() {
    init_tracing();

    // Root/request span that should be the parent of all lifecycle stages.
    let request_span = info_span!(
        "request",
        request_id = 123,
        method = "GET",
        path = "/",
    );

    let ctx = Arc::new(RequestCtx { request_span });

    // Simulate stages being invoked later and potentially on different threads.
    // Stage 1 uses `enter()` inside the callback.
    let h1 = {
        let ctx = ctx.clone();
        tokio::spawn(async move {
            tokio::time::sleep(Duration::from_millis(20)).await;
            stage_1(ctx).await;
        })
    };

    // Stage 2 uses `Instrument` at the call site (common for trait callbacks).
    let h2 = {
        let ctx = ctx.clone();
        let parent = ctx.request_span.clone();
        tokio::spawn(
            async move {
                tokio::time::sleep(Duration::from_millis(120)).await;
                stage_2(ctx).await;
            }
            .instrument(parent),
        )
    };

    let _ = tokio::join!(h1, h2);

    // Flush OTEL.
    opentelemetry::global::shutdown_tracer_provider();
}
