    pub struct Boo;

    impl al::Rest for Foo {
        fn get(&self, path: &str) -> String {
            format!("Foo GET {path}")
        }

        fn post(&self, path: &str, body: &str) -> String {
            format!("Foo POST {path} body={body}")
        }
    }

    impl al::Rest for Boo {
        fn get(&self, path: &str) -> String {
            format!("Boo GET {path}")
        }

        fn post(&self, path: &str, body: &str) -> String {
            format!("Boo POST {path} body={body}")
        }
    }
}

// --- "bl" crate (business layer): wants enum_dispatch, but can't place enum with al::Rest ---
// Solution: define a *local wrapper trait* (same API) for enum_dispatch,
// and forward it to the real trait via a blanket impl.
mod bl {
    use super::{al, il};
    use enum_dispatch::enum_dispatch;

    // This trait must live in the same crate/module as the enum for enum_dispatch.
    // In a multi-crate layout, this would live in your "bl" crate (or a small
    // dedicated "dispatch" crate).
    #[enum_dispatch]
    pub trait Rest {
        fn get(&self, path: &str) -> String;
        fn post(&self, path: &str, body: &str) -> String;
    }

    // One-time forwarding glue: any type implementing al::Rest automatically implements bl::Rest.
    // You only write these ~20 methods once, not for every enum.
    impl<T> Rest for T
    where
        T: al::Rest,
    {
        fn get(&self, path: &str) -> String {
            al::Rest::get(self, path)
        }

        fn post(&self, path: &str, body: &str) -> String {
            al::Rest::post(self, path, body)
        }
    }

    // Now enum_dispatch works without moving al::Rest.
    #[enum_dispatch(Rest)]
    pub enum Item {
        Foo(il::Foo),
        Boo(il::Boo),
    }

    // Re-export for convenience (typical in a real "bl" crate).
    pub use Item as Service;
}

fn main() {
    use bl::Rest as _; // bring the wrapper trait into scope

    // enum_dispatch generates From<Foo> for Item, etc.
    let a: bl::Service = il::Foo.into();
