impl MdxParsingResult {
    fn serialize_to_flatbuffer(&self) -> Vec<u8> {
        // IMPORTANT: FlatBufferBuilder is inherently single-threaded/mutable.
        // You cannot safely (or ergonomically) share &mut FlatBufferBuilder across threads.
        // Rayon closures are `Fn` (not `FnMut`), and even if you used a Mutex,
        // the offsets you create are tied to *one* builder and must be created
        // in that builder's mutation order.
        //
        // The typical pattern is:
        //   1) do CPU-heavy preprocessing in parallel (produce owned data)
        //   2) do the FlatBufferBuilder writes on one thread

