                    .par_iter()
                    .map(|s| s.trim().to_ascii_lowercase())
                    .collect()
            })
            .unwrap_or_default();

        // 2) Build the flatbuffer single-threaded.
        let mut builder = FlatBufferBuilder::new();

        let content_off = builder.create_string(&self.content);

        // Create string offsets sequentially in the SAME builder.
        let ignored_offsets: Vec<WIPOffset<&str>> = ignored_processed
            .iter()
            .map(|s| builder.create_string(s))
            .collect();

        let ignored_vec_off = builder.create_vector(&ignored_offsets);

        let root = fb::create_mdx_parsing_result(
            &mut builder,
            &fb::MdxParsingResultArgs {
                content: Some(content_off),
                ignored_parsers: Some(ignored_vec_off),
            },
        );

        builder.finish(root, None);
        builder.finished_data().to_vec()
    }
