fn common_blob_headers(token: &str) -> Result<HeaderMap> {
    // For AAD Bearer auth, Azure Storage expects x-ms-date + x-ms-version.
    // (Even though the request is authenticated via Authorization header.)
    let mut h = HeaderMap::new();

    let auth = format!("Bearer {token}");
    h.insert(
