fn parse_list_blobs_xml(xml: &str) -> Result<(Vec<String>, Option<String>)> {
    let mut reader = Reader::from_str(xml);
    reader.config_mut().trim_text(true);

    let mut buf = Vec::new();

    let mut names: Vec<String> = Vec::new();
    let mut next_marker: Option<String> = None;

    // Track which tag's text we are reading
    let mut in_name = false;
    let mut in_next_marker = false;

    loop {
        match reader.read_event_into(&mut buf) {
            Ok(Event::Start(e)) => {
                match e.name().as_ref() {
                    b"Name" => in_name = true,
                    b"NextMarker" => in_next_marker = true,
                    _ => {}
                }
            }
            Ok(Event::End(e)) => {
                match e.name().as_ref() {
                    b"Name" => in_name = false,
                    b"NextMarker" => in_next_marker = false,
                    _ => {}
                }
            }
            Ok(Event::Text(t)) => {
                let text = t.unescape()?.to_string();
                if in_name {
                    names.push(text);
                } else if in_next_marker {
                    next_marker = Some(text);
                }
            }
            Ok(Event::Eof) => break,
            Err(e) => return Err(anyhow!("xml read error: {e}")),
            _ => {}
        }
        buf.clear();
    }

    Ok((names, next_marker))
}

