            return Err(anyhow!("json parse error for {blob_name}: {e}"));
        }
    };

    Ok(Some(parsed))
}

fn blob_url(account: &str, container: &str, blob_name: &str) -> Result<Url> {
    // Build URL with proper percent-encoding per path segment, while preserving '/' in blob names.
    let mut url = Url::parse(&format!("https://{account}.blob.core.windows.net/"))?;
