#[component]
fn DragProvider(children: Element) -> Element {
    let active_id = use_signal(|| None::<usize>);
    let is_dragging = use_signal(|| false);

    // Provide the hub in context.
    let hub = use_context_provider(move || DragHub {
        active_id,
        is_dragging,
        listeners: Rc::new(RefCell::new(Vec::new())),
    });

    rsx! {
        // Wrap everything in a div that captures mouse events even when the mouse leaves a circle.
        div {
            // Make this element the coordinate space for mouse events.
            // (We use client_coordinates in this example, so coordinate space is window; either works if consistent.)
            onmousemove: move |me| {
                if *hub.is_dragging.read() {
                    let p = me.client_coordinates();
                    hub.emit(DragMsg::Move(Pt::new(p.x, p.y)));
                }
            },
            onmouseup: move |_| {
                if *hub.is_dragging.read() {
                    hub.is_dragging.set(false);
                    hub.active_id.set(None);
                    hub.emit(DragMsg::End);
                }
            },
            onmouseleave: move |_| {
                if *hub.is_dragging.read() {
                    hub.is_dragging.set(false);
                    hub.active_id.set(None);
                    hub.emit(DragMsg::End);
                }
            },
            {children}
        }
    }
}

