#[component]
fn Point(props: PointProps) -> Element {
    let hub = use_context::<DragHub>();

    let pos = use_signal(|| Pt::new(props.x, props.y));

    // Only this point cares about its own grab offset.
    let grab_offset = use_signal(|| Pt::new(0.0, 0.0));
    let is_me_dragging = use_signal(|| false);

    // Register a custom "drag move" listener once.
    // This lets the provider call into children without storing `EventHandler<'a, T>` in context.
    {
        let hub = hub.clone();
        let pos = pos;
        let grab_offset = grab_offset;
        let is_me_dragging = is_me_dragging;
        let my_id = props.id;

        use_hook(move || {
            hub.register(Callback::new(move |msg: DragMsg| {
                // Route events: only the active point updates.
                let active = *hub.active_id.peek();
                let dragging = *hub.is_dragging.peek();
                if active != Some(my_id) {
                    return;
                }

                match msg {
                    DragMsg::Move(mouse) if dragging && *is_me_dragging.peek() => {
                        let off = *grab_offset.peek();
                        pos.set(Pt::new(mouse.x + off.x, mouse.y + off.y));
                    }
                    DragMsg::End => {
                        is_me_dragging.set(false);
                    }
                    _ => {}
                }
            }));
        });
    }

    rsx! {
        circle {
            class: "p",
            cx: pos.read().x,
            cy: pos.read().y,
            r: 10,
            fill: props.fill,
            stroke: "#222",
            stroke_width: 1,

            onmousedown: move |me| {
                // Mark this point as active.
                hub.active_id.set(Some(props.id));
                hub.is_dragging.set(true);
                is_me_dragging.set(true);

                // Compute offset so the point doesn't jump when you click off-center.
                let m = me.client_coordinates();
                let p = *pos.peek();
                grab_offset.set(Pt::new(p.x - m.x, p.y - m.y));
            },
        }
    }
}
