/// Put stdin into raw mode so we can forward *keypresses* (not just lines).
/// Returns the original termios so it can be restored.
fn stdin_raw_mode() -> Result<Termios> {
    let fd: RawFd = std::io::stdin().as_raw_fd();
    let orig = tcgetattr(fd).context("tcgetattr(stdin)")?;

    let mut raw = orig.clone();
    cfmakeraw(&mut raw);
    tcsetattr(fd, SetArg::TCSANOW, &raw).context("tcsetattr(stdin raw)")?;

    Ok(orig)
}

fn restore_stdin(orig: &Termios) -> Result<()> {
    let fd: RawFd = std::io::stdin().as_raw_fd();
    tcsetattr(fd, SetArg::TCSANOW, orig).context("tcsetattr(stdin restore)")?;
    Ok(())
}

/// Single-owner PTY loop: one thread owns `Session` and performs both read + write.
/// Outgoing keystrokes arrive via a channel, so no mutex is needed.
fn pty_task(mut session: Session, rx: Receiver<Vec<u8>>) -> Result<()> {
    // Make PTY master non-blocking so `read()` never holds the thread forever.
    // We still use poll(2) to avoid busy looping.
    let fd = session.as_raw_fd();
    let old = OFlag::from_bits_truncate(
        fcntl(fd, FcntlArg::F_GETFL).context("fcntl(F_GETFL)")?,
    );
    let new = old | OFlag::O_NONBLOCK;
    fcntl(fd, FcntlArg::F_SETFL(new)).context("fcntl(F_SETFL, O_NONBLOCK)")?;

    let mut stdout = std::io::stdout().lock();
    let mut buf = [0u8; 4096];

    // Demo: run a loop that *waits for a single key* repeatedly.
    // This is the exact state that usually reveals full-duplex problems.
    // (If writes are blocked behind a read-lock, the child appears frozen here.)
    session
        .send(
            "echo 'PTY ready.'\n\
             echo 'Type keys; press q to exit child.'\n\
             while true; do \
               read -n 1 -p 'press a key (q quits): ' k; echo; \
               echo \"you pressed: [$k]\"; \
               if [ \"$k\" = 'q' ]; then exit; fi; \
             done\n",
        )
        .context("send demo script")?;

    loop {
        // 1) Drain all pending outbound bytes and write them.
        //    (No mutex: this thread is the only owner of `session`.)
        while let Ok(data) = rx.try_recv() {
            // If the sender is forwarding raw keystrokes, keep them as-is.
            // `Session::send` takes &str, so use write_all for arbitrary bytes.
            session
                .write_all(&data)
                .context("write_all(to pty)")?;
            session.flush().ok();
        }

        // 2) Wait (briefly) for PTY output.
        let mut fds = [PollFd::new(fd, PollFlags::POLLIN)];
        // Small timeout keeps latency low for writes even if there's no output.
        let _ = poll(&mut fds, 20).context("poll(pty)")?;

        // 3) Read all available PTY output (non-blocking).
        loop {
            match session.read(&mut buf) {
                Ok(0) => {
                    writeln!(stdout, "\r\n[child exited]")?;
                    stdout.flush()?;
                    return Ok(());
                }
                Ok(n) => {
                    stdout.write_all(&buf[..n])?;
                    stdout.flush()?;
                }
                Err(e) if e.kind() == std::io::ErrorKind::WouldBlock => {
                    break;
                }
                Err(e) => return Err(e).context("read(from pty)"),
            }
        }

        // 4) If all senders are gone and the child is quiet, we can exit.
        if rx.is_disconnected() {
            // Give the child a moment; in real apps you'd decide your own policy.
            std::thread::sleep(Duration::from_millis(50));
        }
    }
