fn column_means(m: &DMatrix<f64>) -> RowDVector<f64> {
    let (n, k) = m.shape();
    let mut sums = vec![0.0f64; k];

    for i in 0..n {
        for j in 0..k {
            sums[j] += m[(i, j)];
        }
    }

    for j in 0..k {
        sums[j] /= n as f64;
    }

    RowDVector::from_row_slice(&sums)
}

fn main() {
    // n x k data matrix: rows are observations, columns are variables.
    let x = DMatrix::from_row_slice(
        4,
        3,
        &[
            1.0, 2.0, 3.0, //
            2.0, 3.0, 5.0, //
            4.0, 6.0, 8.0, //
            7.0, 9.0, 10.0,
        ],
    );

    let (n, k) = x.shape();

    // 1 x k row vector of column means.
    let mean = column_means(&x);

    // Broadcast by repeating the 1 x k mean row n times -> n x k.
    let centered = &x - mean.clone().repeat(n, 1);

    // Sample covariance: (Xc^T Xc) / (n-1)
    let cov = (&centered.transpose() * &centered) / ((n as f64) - 1.0);

    println!("X ({}x{}):\n{}\n", n, k, x);
    println!("mean (1x{}):\n{}\n", k, mean);
    println!("centered ({}x{}):\n{}\n", n, k, centered);
    println!("cov ({}x{}):\n{}\n", k, k, cov);

