use std::{
    future::Future,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};

#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

fn try_poll<X, F>(mut future: Pin<&mut F>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    // We just want a synchronous "peek". If the future returns Pending,
    // we'll immediately arrange for it to be polled properly by Tokio.
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match future.as_mut().poll(&mut cx) {
        Poll::Ready(x) => TryPollResult::Ready(x),
        Poll::Pending => TryPollResult::Pending,
    }
}

/// Non-async function, called from async context.
///
/// - If the future is ready right now, returns `Some(output)`.
/// - If it's pending, spawns a Tokio task that awaits it, returns `None`.
fn consume_or_spawn<F>(mut fut: Pin<Box<F>>) -> Option<F::Output>
where
    F: Future + Send + 'static,
    F::Output: Send + std::fmt::Debug + 'static,
{
    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(x) => Some(x),
        TryPollResult::Pending => {
            tokio::spawn(async move {
                let out = fut.await;
                println!("future completed in spawned task: {out:?}");
            });
            None
        }
    }
}

#[tokio::main]
async fn main() {
    println!("--- immediate ready future ---");
    let fut1 = Box::pin(async { 123i32 });
    let got = consume_or_spawn(fut1);
    println!("consume_or_spawn returned: {got:?}");

    println!("\n--- pending future (oneshot + delay) ---");
    let (tx, rx) = tokio::sync::oneshot::channel::<&'static str>();

    tokio::spawn(async move {
        tokio::time::sleep(Duration::from_millis(200)).await;
        let _ = tx.send("hello from oneshot");
    });

    let fut2 = Box::pin(async move {
        rx.await.expect("sender dropped")
    });

    let got = consume_or_spawn(fut2);
    println!("consume_or_spawn returned: {got:?}");

    // Give the spawned task time to finish so you can see its output.
    tokio::time::sleep(Duration::from_millis(500)).await;
}
