async fn queue_worker(shutdown: CancellationToken) {
    info!("queue: started");

    let mut next_id: u64 = 1;
    let mut join_set = JoinSet::new();
    let mut tick = tokio::time::interval(Duration::from_millis(700));

    loop {
        tokio::select! {
            _ = shutdown.cancelled() => {
                info!("queue: shutdown requested; stop accepting new jobs");
                break;
            }
            _ = tick.tick() => {
                let id = next_id;
                next_id += 1;
                info!("queue: received job #{id}");
                join_set.spawn(process_job(id));
            }
        }
    }

    // Graceful shutdown: wait for already-started jobs to finish.
    info!("queue: draining {} in-flight job(s)", join_set.len());
    while let Some(res) = join_set.join_next().await {
        if let Err(e) = res {
            error!("queue: job join error: {e}");
        }
    }

    info!("queue: stopped");
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init();

    let shutdown = CancellationToken::new();

    // ---- Start HTTP server (do NOT detach it without awaiting it somewhere) ----
    let server = HttpServer::new(|| App::new().service(index))
        .bind(("127.0.0.1", 8080))?
        .run();

    // Keep a handle so we can request a graceful stop.
    let server_handle = server.handle();

    // Pin the server future so we can await it in tokio::select!.
    tokio::pin!(server);

    // ---- Start queue worker task ----
    let queue_task = tokio::spawn(queue_worker(shutdown.clone()));

    info!("ready: http://127.0.0.1:8080  (Ctrl+C to stop)");

    // ---- Wait for Ctrl+C OR unexpected server exit ----
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            info!("ctrl-c received: shutting down...");
        }
        res = &mut server => {
            // If the server stops on its own, still shut down the queue.
            match res {
                Ok(()) => info!("http server exited"),
                Err(e) => error!("http server error: {e}"),
            }
        }
    }

    // ---- Trigger graceful shutdown for both subsystems ----
    shutdown.cancel();
    server_handle.stop(true).await; // true = graceful (finish in-flight requests)

    // Ensure server is fully down (if Ctrl+C branch won, server is still pending here).
    let _ = (&mut server).await;

    // Ensure queue finishes draining its in-flight work.
    if let Err(e) = queue_task.await {
        error!("queue task join error: {e}");
    }

    info!("shutdown complete");
    Ok(())
}
