use futures_util::{sink::SinkExt, stream::StreamExt};
use std::{env, net::SocketAddr, sync::Arc};
use tower_http::cors::CorsLayer;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

#[derive(Clone)]
struct AppState {
    allowed_origin: Arc<str>,
}

#[tokio::main]
async fn main() {
    tracing_subscriber::registry()
        .with(tracing_subscriber::EnvFilter::try_from_default_env().unwrap_or_else(|_| {
            // example: RUST_LOG=debug
            "info".into()
        }))
        .with(tracing_subscriber::fmt::layer())
        .init();

    // For local testing, you can run:
    // ALLOWED_ORIGIN=http://localhost:5173 cargo run
    let allowed_origin = env::var("ALLOWED_ORIGIN").unwrap_or_else(|_| "https://www.example.com".to_string());

    let state = AppState {
        allowed_origin: Arc::from(allowed_origin),
    };

    // CORS is for normal HTTP requests, not for enforcing WebSocket origin checks.
    // WebSocket origin filtering is done below via middleware.
    let cors = CorsLayer::new()
        .allow_origin(
            state
                .allowed_origin
                .as_ref()
                .parse::<HeaderValue>()
                .expect("ALLOWED_ORIGIN must be a valid header value"),
        )
        .allow_methods([Method::GET, Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    let app = Router::new()
        .route("/", get(root))
        .route(
            "/client/:session_id",
            get(ws_handler)
                // Apply the origin check ONLY to this WebSocket route.
                .route_layer(middleware::from_fn_with_state(
                    state.clone(),
                    require_origin,
                )),
        )
        .layer(cors)
        .with_state(state);

    let addr: SocketAddr = "127.0.0.1:3000".parse().unwrap();
    tracing::info!(%addr, "listening");

    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    axum::serve(listener, app).await.unwrap();
}

async fn root(State(state): State<AppState>) -> impl IntoResponse {
    format!(
        "OK. Allowed WebSocket Origin: {}\nTry: ws://127.0.0.1:3000/client/abc\n",
        state.allowed_origin
    )
}

/// Middleware that enforces a specific `Origin` header value.
///
/// This runs during the WebSocket handshake (which is an HTTP GET request).
async fn require_origin(
    State(state): State<AppState>,
    req: Request<axum::body::Body>,
    next: Next,
) -> Response {
    let Some(origin) = req.headers().get(header::ORIGIN) else {
        return StatusCode::FORBIDDEN
            .into_response();
    };

    let Ok(origin_str) = origin.to_str() else {
        return StatusCode::FORBIDDEN.into_response();
    };

    if origin_str != state.allowed_origin.as_ref() {
        tracing::warn!(origin = %origin_str, allowed = %state.allowed_origin, "blocked websocket origin");
        return StatusCode::FORBIDDEN.into_response();
    }

    next.run(req).await
}

async fn ws_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: axum::extract::ws::WebSocket, session_id: String) {
    tracing::info!(%session_id, "websocket connected");

    while let Some(Ok(msg)) = socket.next().await {
        // Echo text/binary; ignore other message types.
        match msg {
            axum::extract::ws::Message::Text(t) => {
                let reply = format!("[{session_id}] echo: {t}");
                if socket
                    .send(axum::extract::ws::Message::Text(reply))
                    .await
                    .is_err()
                {
                    break;
                }
            }
            axum::extract::ws::Message::Binary(b) => {
                if socket
                    .send(axum::extract::ws::Message::Binary(b))
                    .await
                    .is_err()
                {
                    break;
                }
            }
            axum::extract::ws::Message::Close(_) => break,
            _ => {}
        }
    }

    tracing::info!(%session_id, "websocket disconnected");
}
