use std::thread::{self, JoinHandle};
use std::time::Duration;

#[cfg(unix)]
use signal_hook::consts::{SIGINT, SIGTERM};
#[cfg(unix)]
use signal_hook::iterator::Signals;

#[derive(Debug)]
enum Message {
    Key(char),
    FileEvent(String),
    #[cfg(unix)]
    Signal(i32),
    Quit,
}

fn spawn_keys(tx: Sender<Message>, shutdown: Arc<AtomicBool>) -> JoinHandle<()> {
    thread::spawn(move || {
        let _ = enable_raw_mode();

        // Poll with a timeout so we can observe `shutdown` without blocking forever.
        while !shutdown.load(Ordering::Relaxed) {
            match event::poll(Duration::from_millis(100)) {
                Ok(true) => {
                    if let Ok(Event::Key(k)) = event::read() {
                        if let KeyCode::Char(c) = k.code {
                            if c == 'q' {
                                shutdown.store(true, Ordering::SeqCst);
                                let _ = tx.send(Message::Quit);
                                break;
                            } else {
                                let _ = tx.send(Message::Key(c));
                            }
                        }
                    }
                }
                Ok(false) => {
                    // timeout
                }
                Err(_) => break,
            }
        }

        let _ = disable_raw_mode();
    })
}

fn spawn_file_watcher(
    tx: Sender<Message>,
    shutdown: Arc<AtomicBool>,
    path: PathBuf,
) -> JoinHandle<()> {
    thread::spawn(move || {
        // Bridge notify's callback into a channel so we can also check `shutdown`.
        let (evt_tx, evt_rx) = crossbeam_channel::unbounded::<notify::Result<notify::Event>>();

        let mut watcher = match recommended_watcher(move |res| {
            let _ = evt_tx.send(res);
        }) {
            Ok(w) => w,
            Err(e) => {
                let _ = tx.send(Message::FileEvent(format!(
                    "failed to create watcher: {e}"
                )));
                return;
            }
        };

        if let Err(e) = watcher.watch(&path, RecursiveMode::NonRecursive) {
            let _ = tx.send(Message::FileEvent(format!("watch error: {e}")));
            return;
        }

        while !shutdown.load(Ordering::Relaxed) {
            match evt_rx.recv_timeout(Duration::from_millis(200)) {
                Ok(Ok(ev)) => {
                    let _ = tx.send(Message::FileEvent(format!(
                        "kind={:?} paths={:?}",
                        ev.kind, ev.paths
                    )));
                }
                Ok(Err(e)) => {
                    let _ = tx.send(Message::FileEvent(format!("notify error: {e}")));
                }
                Err(RecvTimeoutError::Timeout) => {}
                Err(RecvTimeoutError::Disconnected) => break,
            }
        }
        // Dropping `watcher` stops file watching.
    })
}

#[cfg(unix)]
fn spawn_signals(
    mut signals: Signals,
    tx: Sender<Message>,
    shutdown: Arc<AtomicBool>,
) -> JoinHandle<()> {
    thread::spawn(move || {
        // This blocks waiting for the next signal.
        // To stop it from another thread, the main thread calls `signals_handle.close()`.
        for sig in signals.forever() {
            let _ = tx.send(Message::Signal(sig));
            shutdown.store(true, Ordering::SeqCst);
            let _ = tx.send(Message::Quit);
            break;
        }
    })
}

fn main() {
    let (tx, rx): (Sender<Message>, Receiver<Message>) = crossbeam_channel::unbounded();
    let shutdown = Arc::new(AtomicBool::new(false));

    let watch_path = std::env::current_dir().expect("current_dir");

    eprintln!(
        "Running. Press 'q' to quit. Modify any file in: {}",
        watch_path.display()
    );
    eprintln!("(On Unix, Ctrl+C also quits.)\n");

    let key_thread = spawn_keys(tx.clone(), shutdown.clone());
    let watch_thread = spawn_file_watcher(tx.clone(), shutdown.clone(), watch_path);

    #[cfg(unix)]
    let (signal_thread, signals_handle) = {
        let signals = Signals::new([SIGINT, SIGTERM]).expect("register signals");
        let handle = signals.handle();
        let t = spawn_signals(signals, tx.clone(), shutdown.clone());
        (Some(t), Some(handle))
    };

    #[cfg(not(unix))]
    let (signal_thread, signals_handle) = (None::<JoinHandle<()>>, None::<()>);

    // Event loop
    while !shutdown.load(Ordering::Relaxed) {
        match rx.recv_timeout(Duration::from_millis(250)) {
            Ok(Message::Quit) => {
                shutdown.store(true, Ordering::SeqCst);
                break;
            }
            Ok(msg) => {
                println!("event: {msg:?}");
            }
            Err(RecvTimeoutError::Timeout) => {}
            Err(RecvTimeoutError::Disconnected) => break,
        }
    }

    // Global shutdown
    shutdown.store(true, Ordering::SeqCst);

    // Unblock the signal thread if it's waiting.
    #[cfg(unix)]
    if let Some(handle) = signals_handle {
        handle.close();
    }

    let _ = key_thread.join();
    let _ = watch_thread.join();

    #[cfg(unix)]
    if let Some(t) = signal_thread {
        let _ = t.join();
    }

    // Ensure raw mode is disabled even if key thread exited unexpectedly.
    let _ = disable_raw_mode();

    eprintln!("Exited cleanly.");
}
"
}
