// ----------------------------
// Custom asset type + loader
// ----------------------------

#[derive(Asset, TypePath, Debug, Clone)]
struct MyText(String);

#[derive(Default)]
struct MyTextLoader;

impl AssetLoader for MyTextLoader {
    type Asset = MyText;
    type Settings = ();
    type Error = std::io::Error;

    fn extensions(&self) -> &[&str] {
        &["txt"]
    }

    fn load<'a>(
        &'a self,
        reader: &'a mut Reader,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            let mut bytes = Vec::new();
            reader.read_to_end(&mut bytes).await?;
            Ok(MyText(String::from_utf8_lossy(&bytes).into_owned()))
        })
    }
}

// ----------------------------
// A tiny "PAK0" archive format
// ----------------------------
//
// File layout:
//   magic: [u8;4] = b"PAK0"
//   num_entries: u32 (LE)
//   entries[num_entries]:
//     name_len: u16 (LE)
//     name: [u8; name_len] (UTF-8, e.g. "hello.txt" or "dir/a.bin")
//     offset: u64 (LE)
//     len: u64 (LE)
//   data blobs...
//
// The key part: the reader can seek directly to (offset,len) for a requested entry,
// instead of loading/decoding thousands of entries eagerly.

#[derive(Debug, Clone)]
struct PakEntry {
    offset: u64,
    len: u64,
}

#[derive(Debug, Clone)]
struct PakIndex {
    entries: HashMap<String, PakEntry>,
}

fn read_u16_le(r: &mut impl Read) -> std::io::Result<u16> {
    let mut b = [0u8; 2];
    r.read_exact(&mut b)?;
    Ok(u16::from_le_bytes(b))
}
fn read_u32_le(r: &mut impl Read) -> std::io::Result<u32> {
    let mut b = [0u8; 4];
    r.read_exact(&mut b)?;
    Ok(u32::from_le_bytes(b))
}
fn read_u64_le(r: &mut impl Read) -> std::io::Result<u64> {
    let mut b = [0u8; 8];
    r.read_exact(&mut b)?;
    Ok(u64::from_le_bytes(b))
}

fn parse_index(mut f: &mut File) -> std::io::Result<PakIndex> {
    f.seek(SeekFrom::Start(0))?;

    let mut magic = [0u8; 4];
    f.read_exact(&mut magic)?;
    if &magic != b"PAK0" {
        return Err(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            "bad magic",
        ));
    }

    let n = read_u32_le(&mut f)? as usize;
    let mut entries = HashMap::with_capacity(n);
    for _ in 0..n {
        let name_len = read_u16_le(&mut f)? as usize;
        let mut name_bytes = vec![0u8; name_len];
        f.read_exact(&mut name_bytes)?;
        let name = String::from_utf8(name_bytes)
            .map_err(|_| std::io::Error::new(std::io::ErrorKind::InvalidData, "bad utf-8 name"))?;
        let offset = read_u64_le(&mut f)?;
        let len = read_u64_le(&mut f)?;
        entries.insert(name, PakEntry { offset, len });
    }

    Ok(PakIndex { entries })
}

// ----------------------------
// Custom AssetReader for pak://...
// ----------------------------

struct PakAssetReader {
    // On-disk root for locating the archive file (e.g. ./assets).
    root: PathBuf,
    // Cache parsed indices so we don't re-read the directory on every request.
    index_cache: Mutex<HashMap<PathBuf, PakIndex>>,
}

impl PakAssetReader {
    fn new(root: impl Into<PathBuf>) -> Self {
        Self {
            root: root.into(),
            index_cache: Mutex::new(HashMap::new()),
        }
    }

    /// If `path` contains a component ending with `.pak`, split it into:
    ///   (archive_path_relative_to_root, inner_path_inside_archive)
    ///
    /// Example: "paks/demo.pak/hello.txt" -> ("paks/demo.pak", "hello.txt")
    fn split_archive_path(path: &Path) -> Option<(PathBuf, String)> {
        let mut acc = PathBuf::new();
        let mut comps = path.components().peekable();

        while let Some(c) = comps.next() {
            let s = c.as_os_str().to_string_lossy();
            acc.push(c);
            if s.ends_with(".pak") {
                // Remaining components are the inner path
                let mut inner_parts: Vec<String> = Vec::new();
                while let Some(rest) = comps.next() {
                    inner_parts.push(rest.as_os_str().to_string_lossy().to_string());
                }
                if inner_parts.is_empty() {
                    return None;
                }
                let inner = inner_parts.join("/");
                return Some((acc, inner));
            }
        }
        None
    }

    fn read_from_filesystem(&self, path: &Path) -> Result<Vec<u8>, AssetReaderError> {
        let full = self.root.join(path);
        fs::read(&full).map_err(|e| {
            if e.kind() == std::io::ErrorKind::NotFound {
                AssetReaderError::NotFound(full)
            } else {
                AssetReaderError::Io(e)
            }
        })
    }

    fn get_or_load_index(&self, archive_rel: &Path) -> Result<PakIndex, AssetReaderError> {
        let archive_full = self.root.join(archive_rel);

        // Fast path: cache hit
        if let Some(idx) = self
            .index_cache
            .lock()
            .unwrap()
            .get(&archive_full)
            .cloned()
        {
            return Ok(idx);
        }

        let mut f = File::open(&archive_full).map_err(|e| {
            if e.kind() == std::io::ErrorKind::NotFound {
                AssetReaderError::NotFound(archive_full.clone())
            } else {
                AssetReaderError::Io(e)
            }
        })?;

        let idx = parse_index(&mut f).map_err(AssetReaderError::Io)?;
        self.index_cache
            .lock()
            .unwrap()
            .insert(archive_full, idx.clone());
        Ok(idx)
    }

    fn read_from_archive(&self, archive_rel: &Path, inner: &str) -> Result<Vec<u8>, AssetReaderError> {
        let archive_full = self.root.join(archive_rel);
        let idx = self.get_or_load_index(archive_rel)?;
        let ent = idx.entries.get(inner).ok_or_else(|| {
            AssetReaderError::NotFound(self.root.join(archive_rel).join(inner))
        })?;

        let mut f = File::open(&archive_full).map_err(AssetReaderError::Io)?;
        f.seek(SeekFrom::Start(ent.offset))
            .map_err(AssetReaderError::Io)?;

        let mut buf = vec![0u8; ent.len as usize];
        f.read_exact(&mut buf).map_err(AssetReaderError::Io)?;
        Ok(buf)
    }
}

impl AssetReader for PakAssetReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        Box::pin(async move {
            let bytes = if let Some((archive_rel, inner)) = Self::split_archive_path(path) {
                self.read_from_archive(&archive_rel, &inner)?
            } else {
                self.read_from_filesystem(path)?
            };
            Ok(Box::new(VecReader::new(bytes)))
        })
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<dyn Reader>, AssetReaderError>> {
        // This example disables meta_check, so this is mostly unused.
        // If you *do* enable meta, you could map "foo.ext.meta" the same way
        // (filesystem or archive), or just return NotFound.
        Box::pin(async move {
            let bytes = self.read_from_filesystem(path)?;
            Ok(Box::new(VecReader::new(bytes)))
        })
    }

    fn is_directory<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move {
            // Treat anything inside an archive as a file for this demo.
            if Self::split_archive_path(path).is_some() {
                return Ok(false);
            }
            let full = self.root.join(path);
            Ok(full.is_dir())
        })
    }

    fn read_directory<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<PathStream, AssetReaderError>> {
        Box::pin(async move {
            // Minimal implementation:
            // - no directory traversal inside archives for this demo
            // - for real files, delegate to the filesystem
            if Self::split_archive_path(path).is_some() {
                let s = futures_lite::stream::empty::<PathBuf>();
                return Ok(Box::pin(s));
            }

            let full = self.root.join(path);
            let entries = fs::read_dir(&full).map_err(AssetReaderError::Io)?;

            let mut out: Vec<PathBuf> = Vec::new();
            for e in entries {
                let e = e.map_err(AssetReaderError::Io)?;
                if let Ok(p) = e.path().strip_prefix(&self.root) {
                    out.push(p.to_path_buf());
                }
            }

            let s = futures_lite::stream::iter(out);
            Ok(Box::pin(s))
        })
    }
}

// ----------------------------
// Demo asset creation (writes ./assets/paks/demo.pak)
// ----------------------------

fn create_demo_assets() {
    let root = std::env::current_dir().expect("cwd");
    let assets = root.join("assets");
    let paks_dir = assets.join("paks");
    let pak_path = paks_dir.join("demo.pak");

    fs::create_dir_all(&paks_dir).expect("create assets/paks");

    // Overwrite for deterministic demo.
    let entries: Vec<(&str, &[u8])> = vec![
        ("hello.txt", b"Hello from inside a .pak (lazy, per-file extraction)!"),
        (
            "notes/second.txt",
            b"This one exists too, but we never load it in this demo.",
        ),
    ];

    write_pak(&pak_path, &entries).expect("write demo.pak");
}

fn write_u16_le(w: &mut impl Write, v: u16) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}
fn write_u32_le(w: &mut impl Write, v: u32) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}
fn write_u64_le(w: &mut impl Write, v: u64) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}

fn write_pak(path: &Path, entries: &[(&str, &[u8])]) -> std::io::Result<()> {
    let mut f = File::create(path)?;

    // Compute header size to know data offsets.
    let header_size = 4u64
        + 4u64
        + entries
            .iter()
            .map(|(name, _)| 2u64 + name.as_bytes().len() as u64 + 8u64 + 8u64)
            .sum::<u64>();

    // Write magic + count
    f.write_all(b"PAK0")?;
    write_u32_le(&mut f, entries.len() as u32)?;

    // Directory entries (fill offsets deterministically)
    let mut cur_offset = header_size;
    for (name, data) in entries {
        let name_bytes = name.as_bytes();
        write_u16_le(&mut f, name_bytes.len() as u16)?;
        f.write_all(name_bytes)?;
        write_u64_le(&mut f, cur_offset)?;
        write_u64_le(&mut f, data.len() as u64)?;
        cur_offset += data.len() as u64;
    }

    // Data blobs
    for (_, data) in entries {
        f.write_all(data)?;
    }

    Ok(())
}
