type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

/// A tiny single-thread "trampoline" executor.
///
/// Why it exists here:
/// rxRust's local (RefCell-based) operators/subjects are not re-entrant.
/// Feeding values back synchronously (calling `next()` inside a `subscribe()`
/// call stack) can panic with "RefCell already borrowed".
///
/// The trampoline breaks re-entrancy by queueing all `next()` calls and
/// executing them after the current call stack unwinds.
#[derive(Clone, Default)]
struct Trampoline {
    q: Rc<RefCell<VecDeque<Box<dyn FnOnce()>>>>,
    running: Rc<Cell<bool>>,
}

impl Trampoline {
    fn new() -> Self {
        Self::default()
    }

    /// Enqueue a task. If we're not currently draining, start draining.
    fn schedule<F>(&self, f: F)
    where
        F: FnOnce() + 'static,
    {
        self.q.borrow_mut().push_back(Box::new(f));
        if self.running.get() {
            return;
        }
        self.running.set(true);
        loop {
            let task = { self.q.borrow_mut().pop_front() };
            match task {
                Some(t) => t(),
                None => break,
            }
        }
        self.running.set(false);
    }

    /// Run setup code while in "running" mode so any feedback is queued.
    fn run<F, R>(&self, f: F) -> R
    where
        F: FnOnce() -> R,
    {
        if self.running.get() {
            return f();
        }
        self.running.set(true);
        let r = f();
        // Drain anything queued during setup.
        loop {
            let task = { self.q.borrow_mut().pop_front() };
            match task {
                Some(t) => t(),
                None => break,
            }
        }
        self.running.set(false);
        r
    }
}

fn nand(name: &'static str, a: Type, b: Type) -> Type {
