    let r2_box = r2.clone().box_it_clone();

    // Cross-coupled NANDs.
    let q = nand("s", s, s2_box).box_it_clone();
    let nq = nand("r", r, r2_box).box_it_clone();

    // IMPORTANT: feedback must be deferred (trampolined), not synchronous.
    {
        let tr = tr.clone();
        let r2_handle = r2.clone();
        let sub = q.clone().subscribe(move |v| {
            let mut r2 = r2_handle.clone();
            tr.schedule(move || r2.next(v));
        });
        std::mem::forget(sub);
    }
