        std::mem::forget(sub);

        (s, r, q, nq)
    });

    // Drive inputs via the trampoline so feedback is always queued, never re-entrant.
    tr.schedule({
        let mut s = s.clone();
        move || s.next(false)
    });
    tr.schedule({
        let mut s = s.clone();
        move || s.next(true)
    });

    tr.schedule({
        let mut r = r.clone();
        move || r.next(false)
    });
    tr.schedule({
        let mut r = r.clone();
        move || r.next(true)
    });

