/// Ray vs oriented box (OBB) intersection.
/// The box is centered at `center`, rotated by `rot`, with half extents `half`.
/// Returns the hit on the *entry* face (assuming ray starts outside).
fn intersect_ray_obb(ray: Ray3d, center: Vec3, rot: Quat, half: Vec3) -> Option<Hit> {
    let origin_w = ray.origin;
    let dir_w = ray.direction.as_vec3();

    // Transform the ray into the box's local space.
    let inv = rot.inverse();
    let origin = inv * (origin_w - center);
    let dir = inv * dir_w;

    let eps = 1e-6;
    let mut tmin = f32::NEG_INFINITY;
    let mut tmax = f32::INFINITY;
    let mut local_normal_at_tmin = Vec3::ZERO;

    for axis in 0..3 {
        let o = origin[axis];
        let d = dir[axis];
        let min = -half[axis];
        let max = half[axis];

        if d.abs() < eps {
            // Parallel to planes
            if o < min || o > max {
                return None;
            }
            continue;
        }

        let inv_d = 1.0 / d;
        let mut t1 = (min - o) * inv_d;
        let mut t2 = (max - o) * inv_d;
        if t1 > t2 {
            std::mem::swap(&mut t1, &mut t2);
        }

        // For the entry time on this axis: if d>0 you hit the min plane (normal -axis), else max plane (normal +axis).
        let mut n = Vec3::ZERO;
        n[axis] = if d > 0.0 { -1.0 } else { 1.0 };

        if t1 > tmin {
            tmin = t1;
            local_normal_at_tmin = n;
        }
        tmax = tmax.min(t2);

        if tmin > tmax {
            return None;
        }
    }

    if tmax < 0.0 {
        return None;
    }

    let t_hit = if tmin >= 0.0 { tmin } else { tmax };
    if t_hit < 0.0 {
        return None;
    }

    let local_hit_point = origin + dir * t_hit;

    // Which face center do we want? Use the face indicated by the entry normal.
    // (This is stable and gives a clean face center even if the hit point is near an edge.)
    let local_normal = local_normal_at_tmin;
    let local_face_center = local_normal * half; // component-wise scale

    let world_normal = (rot * local_normal).normalize();
    let world_face_center = center + rot * local_face_center;
    let world_hit_point = center + rot * local_hit_point;

    Some(Hit {
        local_normal,
        world_normal,
        world_face_center,
        world_hit_point,
    })
}

/// Given a local face normal (exactly one of ±X, ±Y, ±Z), return two local tangents (u,v)
/// such that (u, v, n) is right-handed.
fn face_tangents(local_normal: Vec3) -> (Vec3, Vec3) {
    // Choose canonical tangents per face, then enforce right-handedness.
    // Base choices (for +axis faces):
    //  +X: u=+Z, v=+Y
    //  +Y: u=+X, v=+Z
    //  +Z: u=+X, v=+Y
    let (mut u, mut v) = if local_normal.x.abs() > 0.5 {
        (Vec3::Z, Vec3::Y)
    } else if local_normal.y.abs() > 0.5 {
        (Vec3::X, Vec3::Z)
    } else {
        (Vec3::X, Vec3::Y)
    };

    // If we are on a negative face, flip one tangent so the basis stays right-handed.
    // We want: u x v = n
    let n = local_normal;
    if u.cross(v).dot(n) < 0.0 {
        u = -u;
    }
    (u, v)
}
