use std::time::Duration;
use tokio::sync::broadcast;
use tokio_stream::wrappers::{
    errors::BroadcastStreamRecvError,
    BroadcastStream,
};
use tokio_util::sync::CancellationToken;

#[derive(Debug, Clone)]
struct Event {
    from: &'static str,
    n: u64,
}

#[derive(Debug, Clone)]
pub struct EventSender {
    tx: broadcast::Sender<Event>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        let _ = self.tx.send(event);
    }
}

/// Factory that can create new subscribers *without* holding a `broadcast::Sender`.
///
/// Important for shutdown:
/// - The broadcast channel only closes when **all `Sender` clones are dropped**.
/// - If your stream factory holds a `Sender`, it can accidentally keep the channel alive.
/// - Holding a single `Receiver` and calling `resubscribe()` avoids that.
#[derive(Debug, Clone)]
pub struct EventStreamFactory {
    rx: std::sync::Arc<Mutex<broadcast::Receiver<Event>>>,
}

#[derive(Debug)]
pub enum RecvError {
    Lagged(u64),
    Closed,
}

pub fn events_channel() -> (EventSender, EventStreamFactory) {
    let (tx, rx) = broadcast::channel(20);
    (
        EventSender { tx },
        EventStreamFactory {
            rx: std::sync::Arc::new(Mutex::new(rx)),
        },
    )
}

impl EventStreamFactory {
    fn subscribe(&self) -> broadcast::Receiver<Event> {
        // This is a short critical section.
        // In real apps you may prefer a non-blocking mutex (e.g. parking_lot) or a different design.
        self.rx.lock().unwrap().resubscribe()
    }

    pub fn all_events(
        &self,
    ) -> impl futures_util::Stream<Item = Result<Event, RecvError>> + Send + 'static {
        let rx = self.subscribe();
        BroadcastStream::new(rx).map(|item| match item {
            Ok(ev) => Ok(ev),
            Err(BroadcastStreamRecvError::Lagged(n)) => Err(RecvError::Lagged(n)),
            Err(BroadcastStreamRecvError::Closed) => Err(RecvError::Closed),
        })
    }
}

async fn producer(name: &'static str, tx: EventSender, shutdown: CancellationToken) {
    let mut n = 0u64;
    loop {
        tokio::select! {
            _ = shutdown.cancelled() => {
                eprintln!("producer {name}: shutting down (dropping its Sender clone)");
                break;
            }
            _ = tokio::time::sleep(Duration::from_millis(250)) => {
                n += 1;
                tx.send(Event { from: name, n });
            }
        }
    }
}

async fn consumer(factory: EventStreamFactory) {
    let mut stream = factory.all_events();

    while let Some(item) = stream.next().await {
        match item {
            Ok(ev) => println!("consumer: got event: {ev:?}"),
            Err(RecvError::Lagged(n)) => eprintln!("consumer: lagged by {n}"),
            Err(RecvError::Closed) => {
                eprintln!("consumer: channel closed (all Senders dropped); stream ends");
                break;
            }
        }
    }

    eprintln!("consumer: done");
}

#[tokio::main]
async fn main() {
    let (events_tx, events_factory) = events_channel();

    let shutdown = CancellationToken::new();

    // Spawn two producers; each holds a clone of the Sender.
    let p1 = tokio::spawn(producer("p1", events_tx.clone(), shutdown.clone()));
    let p2 = tokio::spawn(producer("p2", events_tx.clone(), shutdown.clone()));

    // Spawn a consumer using BroadcastStream (simulates SSE handler).
    let c = tokio::spawn(consumer(events_factory.clone()));

    // Wait for CTRL+C or auto-shutdown after a few seconds.
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            eprintln!("main: got Ctrl+C");
        }
        _ = tokio::time::sleep(Duration::from_secs(3)) => {
            eprintln!("main: timed shutdown");
        }
    }

    // 1) Tell tasks holding Sender clones to exit.
    shutdown.cancel();

    // 2) Wait for producers to drop their Sender clones.
    let _ = p1.await;
    let _ = p2.await;

    // 3) Now drop the last Sender in main. This closes the broadcast channel,
    //    which causes BroadcastStream to yield Closed and stop.
    drop(events_tx);

    let _ = c.await;
    eprintln!("main: clean shutdown");
}
