use std::collections::{BTreeMap, BTreeSet};

/// A normalized import leaf.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
enum Import {
    /// `use <path>;` (possibly renamed)
    Item { path: Vec<String>, alias: Option<String> },
    /// `use <path>::*;`
    Glob { path: Vec<String> },
}

#[derive(Debug, Default, Clone)]
struct TrieNode {
    /// Import of `self` at this node: `use prefix;` (represented as terminal at the last segment)
    /// Multiple aliases can exist at the same node (rare but possible across separate uses).
    terminals: BTreeSet<Option<String>>,
    glob: bool,
    children: BTreeMap<String, TrieNode>,
}

fn main() {
    let input = r#"
// Some imports we want to rewrite
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};

fn main() {
    println!("hello");
}
"#;

    println!("--- before ---\n{input}");
    let output = rewrite_file_text(input);
    println!("--- after ---\n{output}");
}

fn rewrite_file_text(input: &str) -> String {
    let parse = SourceFile::parse(input);
    let file = parse.tree();
    let root = file.syntax().clone();

    // Collect edits first, then apply back-to-front.
    let mut edits: Vec<(usize, usize, String)> = Vec::new();

    for use_item in root.descendants().filter_map(ast::Use::cast) {
        let Some(tree) = use_item.use_tree() else { continue };

        let mut imports = Vec::new();
        collect_imports(&tree, Vec::new(), &mut imports);

        let mut changed = false;
        for imp in &mut imports {
            changed |= flatten_vexide_devices(imp);
        }
        if !changed {
            continue;
        }

        // Rebuild a compact use-tree from the rewritten leaf imports.
        let rebuilt_tree = render_use_tree_from_imports(&imports);

        let vis = use_item
            .visibility()
            .map(|v| {
                let t = v.syntax().text().to_string();
                if t.trim().is_empty() { String::new() } else { format!("{} ", t.trim()) }
            })
            .unwrap_or_default();

        let replacement = format!("{vis}use {rebuilt_tree};");

        let range = use_item.syntax().text_range();
        let start: usize = range.start().into();
        let end: usize = range.end().into();
        edits.push((start, end, replacement));
    }

    // Apply in reverse order so offsets remain valid.
    edits.sort_by_key(|(s, _, _)| *s);
    let mut out = input.to_string();
    for (start, end, replacement) in edits.into_iter().rev() {
        out.replace_range(start..end, &replacement);
    }

    out
}

/// Collect leaf imports from a `use` tree into a flat list of absolute-ish paths.
///
/// `prefix` holds the accumulated path segments from ancestors.
fn collect_imports(tree: &ast::UseTree, prefix: Vec<String>, out: &mut Vec<Import>) {
    let mut here_prefix = prefix;

    // Path is relative to parent use-tree's path (if any).
    if let Some(p) = tree.path() {
        let segs = split_path_segments(&p.syntax().text().to_string());
        here_prefix.extend(segs);
    }

    // Recurse into `{ ... }`.
    if let Some(list) = tree.use_tree_list() {
        for child in list.use_trees() {
            collect_imports(&child, here_prefix.clone(), out);
        }
        return;
    }

    // Leaf cases
    if tree.star_token().is_some() {
        // `use <prefix>::*` OR `use { * }` (prefix can be empty, though unusual)
        out.push(Import::Glob { path: here_prefix });
        return;
    }

    let alias = tree.rename().and_then(rename_alias);

    // Special-case `self` leaf: `use foo::{self, bar};`
    // In the AST that looks like a child UseTree with `path = self`.
    if let Some(last) = here_prefix.last() {
        if last == "self" {
            let mut p = here_prefix;
            p.pop(); // drop the trailing `self`
            out.push(Import::Item { path: p, alias });
            return;
        }
    }

    // Regular item import: `use <path>;` or `use <path> as <alias>;`
    if !here_prefix.is_empty() {
        out.push(Import::Item {
            path: here_prefix,
            alias,
        });
    }
}

/// Rewrite rule:
/// - `vexide::devices::<rest>` => `vexide::<rest>`
/// - `vexide::devices::*` => `vexide::*`
/// - but keep `use vexide::devices;` unchanged.
fn flatten_vexide_devices(imp: &mut Import) -> bool {
    let (path, is_glob) = match imp {
        Import::Item { path, .. } => (path, false),
        Import::Glob { path } => (path, true),
    };

    if path.len() >= 2 && path[0] == "vexide" && path[1] == "devices" {
        if path.len() >= 3 {
            path.remove(1);
            return true;
        }
        if is_glob {
            // `vexide::devices::*` -> `vexide::*`
            path.remove(1);
            return true;
        }
    }
    false
}

fn render_use_tree_from_imports(imports: &[Import]) -> String {
    let mut root = TrieNode::default();

    for imp in imports {
        match imp {
            Import::Item { path, alias } => {
                insert_item(&mut root, path, alias.clone());
            }
            Import::Glob { path } => {
                insert_glob(&mut root, path);
            }
        }
    }

    render_root(&root)
}

fn insert_item(root: &mut TrieNode, path: &[String], alias: Option<String>) {
    if path.is_empty() {
        // `use self;` at root: ignore for this demo.
        return;
    }

    let mut node = root;
    for seg in path {
        node = node.children.entry(seg.clone()).or_default();
    }
    node.terminals.insert(alias);
}

fn insert_glob(root: &mut TrieNode, path: &[String]) {
    let mut node = root;
    for seg in path {
        node = node.children.entry(seg.clone()).or_default();
    }
    node.glob = true;
}

fn render_root(root: &TrieNode) -> String {
    let mut parts: Vec<String> = Vec::new();

    // Root-level terminals/glob are unusual; render if present.
    for alias in &root.terminals {
        parts.push(render_self_terminal(alias.as_ref()));
    }
    if root.glob {
        parts.push("*".to_string());
    }

    for (seg, child) in &root.children {
        parts.push(render_node(seg, child));
    }

    match parts.len() {
        0 => "{}".to_string(),
        1 => parts.remove(0),
        _ => format!("{{{}}}", parts.join(", ")),
    }
}

fn render_node(seg: &str, node: &TrieNode) -> String {
    let has_children = !node.children.is_empty();
    let terminal_count = node.terminals.len();

    // If this node is *only* a single terminal (no children, no glob), render `seg` or `seg as Alias`.
    if !has_children && !node.glob && terminal_count == 1 {
        let alias = node.terminals.iter().next().unwrap();
        return match alias {
            None => seg.to_string(),
            Some(a) => format!("{seg} as {a}"),
        };
    }

    // If this node is *only* a glob (no children, no terminals), render `seg::*`.
    if !has_children && node.glob && terminal_count == 0 {
        return format!("{seg}::*");
    }

    // Otherwise, we need `seg::{...}` form.
    let mut items: Vec<String> = Vec::new();

    // If importing this node itself alongside children/glob, emit `self` (or `self as Alias`).
    for alias in &node.terminals {
        items.push(render_self_terminal(alias.as_ref()));
    }

    if node.glob {
        items.push("*".to_string());
    }

    for (child_seg, child) in &node.children {
        items.push(render_node(child_seg, child));
    }

    format!("{seg}::{{{}}}", items.join(", "))
}

fn render_self_terminal(alias: Option<&String>) -> String {
    match alias {
        None => "self".to_string(),
        Some(a) => format!("self as {a}"),
    }
}

fn rename_alias(r: ast::Rename) -> Option<String> {
    // `Rename` node text is like `as Foo` (possibly with whitespace)
    let t = r.syntax().text().to_string();
    let t = t.trim();
    let rest = t.strip_prefix("as")?.trim();
    if rest.is_empty() {
        None
    } else {
        Some(rest.to_string())
    }
}

fn split_path_segments(path_text: &str) -> Vec<String> {
    // Good enough for `use` paths; keeps `crate`, `self`, `super`, identifiers.
    // We ignore leading `::` for brevity.
    let mut s = path_text.trim();
    if let Some(stripped) = s.strip_prefix("::") {
        s = stripped;
    }
    if s.is_empty() {
        return vec![];
    }
    s.split("::")
        .map(|x| x.trim())
        .filter(|x| !x.is_empty())
        .map(|x| x.to_string())
        .collect()
}
