tokio = { version = "1.43", features = ["macros", "rt-multi-thread"] }
tokio-postgres = "0.7"
uuid = { version = "1.8", features = ["v4"] }
",
  "main.rs": "use std::env;
use tokio::task::JoinHandle;
use tokio::sync::OnceCell;
use tokio_postgres::{Client, NoTls};
use uuid::Uuid;

#[derive(Debug, Clone)]
struct DbConfig {
    host: String,
    port: u16,
    user: String,
    password: String,
    /// Admin DB to connect to when creating/dropping other DBs (usually "postgres")
    admin_db: String,
}

/// Holds both the `Client` *and* the spawned connection-driving task.
///
/// Important: the `Connection` future must be kept alive (polled) for the `Client` to work.
/// Spawning it is the usual way to do that.
struct CachedConn {
    client: Client,
    _driver: JoinHandle<()>,
}

impl CachedConn {
    fn client(&self) -> Client {
        // `Client` is cheap to clone; returning a clone avoids tricky lifetimes.
        self.client.clone()
    }
}

struct DbAdmin {
    cfg: DbConfig,
    admin: OnceCell<CachedConn>,
}

impl DbAdmin {
    fn new(cfg: DbConfig) -> Self {
        Self {
            cfg,
            admin: OnceCell::const_new(),
        }
    }

    async fn admin_client(&self) -> Result<Client, tokio_postgres::Error> {
        let host = self.cfg.host.clone();
        let port = self.cfg.port;
        let user = self.cfg.user.clone();
        let password = self.cfg.password.clone();
        let admin_db = self.cfg.admin_db.clone();

        let cached = self
            .admin
            .get_or_try_init(|| async move {
                let conn_str = format!(
                    "host={} port={} user={} password={} dbname={}",
                    host, port, user, password, admin_db
                );

                let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;

                let driver = tokio::spawn(async move {
                    if let Err(e) = connection.await {
                        eprintln!("admin connection driver ended: {e}");
                    }
                });

                Ok::<_, tokio_postgres::Error>(CachedConn {
                    client,
                    _driver: driver,
                })
            })
            .await?;

        Ok(cached.client())
    }

    async fn connect_db(&self, dbname: &str) -> Result<CachedConn, tokio_postgres::Error> {
        let conn_str = format!(
            "host={} port={} user={} password={} dbname={}",
            self.cfg.host, self.cfg.port, self.cfg.user, self.cfg.password, dbname
        );

        let (client, connection) = tokio_postgres::connect(&conn_str, NoTls).await?;
        let driver = tokio::spawn(async move {
            if let Err(e) = connection.await {
                eprintln!("db connection driver ended: {e}");
            }
        });

        Ok(CachedConn {
            client,
            _driver: driver,
        })
    }

    async fn create_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let admin = self.admin_client().await?;
        admin
            .execute(&format!("CREATE DATABASE \"{name}\""), &[])
            .await?;

        // Initialize schema in the new DB.
        let db = self.connect_db(name).await?;
        db.client()
            .batch_execute(
                r#"
                CREATE TABLE IF NOT EXISTS demo (
                    id  SERIAL PRIMARY KEY,
                    msg TEXT NOT NULL
                );
                INSERT INTO demo (msg) VALUES ('hello');
                "#,
            )
            .await?;

        Ok(())
    }

    async fn drop_database(&self, name: &str) -> Result<(), tokio_postgres::Error> {
        let admin = self.admin_client().await?;

        // Kill any remaining backends connected to the target DB.
        let terminate_sql = format!(
            "
            SELECT pg_terminate_backend(pid)
            FROM pg_stat_activity
            WHERE datname = '{name}' AND pid <> pg_backend_pid();
            "
        );
        admin.execute(&terminate_sql, &[]).await?;

        admin
            .execute(&format!("DROP DATABASE \"{name}\""), &[])
            .await?;

        Ok(())
    }
}

fn env_or(key: &str, default: &str) -> String {
    env::var(key).unwrap_or_else(|_| default.to_string())
}

#[tokio::main]
async fn main() {
    // Configure via env vars if desired:
    // PGHOST, PGPORT, PGUSER, PGPASSWORD, PGADMINDB
    let cfg = DbConfig {
        host: env_or("PGHOST", "localhost"),
        port: env_or("PGPORT", "5432").parse().unwrap_or(5432),
        user: env_or("PGUSER", "postgres"),
        password: env_or("PGPASSWORD", "postgres"),
        admin_db: env_or("PGADMINDB", "postgres"),
    };

    let admin = DbAdmin::new(cfg);

    let dbname = format!("tmp_{}", Uuid::new_v4().simple());

    println!("Creating database: {dbname}");
    if let Err(e) = admin.create_database(&dbname).await {
        eprintln!("create_database failed: {e}");
        return;
    }

    // Demonstrate it works by connecting and reading.
    match admin.connect_db(&dbname).await {
        Ok(conn) => {
            let row = conn
                .client()
                .query_one("SELECT msg FROM demo LIMIT 1", &[])
                .await;
            match row {
                Ok(row) => {
                    let msg: String = row.get(0);
                    println!("Read from {dbname}.demo: {msg}");
                }
                Err(e) => eprintln!("query failed: {e}"),
            }
        }
        Err(e) => eprintln!("connect_db failed: {e}"),
    }

    println!("Dropping database: {dbname}");
    if let Err(e) = admin.drop_database(&dbname).await {
        eprintln!("drop_database failed: {e}");
    }
}
"
