use std::{collections::HashMap, future::Future, sync::Arc};

// --- Minimal request/response types (library side) ---

#[derive(Debug)]
pub struct Request {
    pub path: String,
}

#[derive(Debug)]
pub struct Response {
    pub body: String,
}

// Unified stored type: (Arc<Request>) -> BoxFuture<'static, Response>
//
// Key idea:
// - We *store* the request as Arc<Request> inside the boxed future.
// - That makes the returned boxed future 'static, even if the user's async
//   handler returns a future that borrows from &Request.
// - This avoids needing a single concrete `Fut` type that works for all 'a.
type HandlerFn = dyn Fn(Arc<Request>) -> BoxFuture<'static, Response> + Send + Sync + 'static;

#[derive(Clone)]
pub struct Handler(Arc<HandlerFn>);

impl Handler {
    pub fn call(&self, req: Arc<Request>) -> BoxFuture<'static, Response> {
        (self.0)(req)
    }
}

// Conversion for an async handler: for<'a> Fn(&'a Request) -> (some future tied to 'a)
//
// The trick is using the Fn trait's associated Output type *per lifetime*:
//   for<'a> <F as Fn(&'a Request)>::Output: Future<Output = Response> + 'a
impl<F> From<F> for Handler
where
    F: for<'a> Fn(&'a Request) + Send + Sync + 'static,
    for<'a> <F as Fn(&'a Request)>::Output: Future<Output = Response> + Send + 'a,
{
    fn from(f: F) -> Self {
        let f = Arc::new(f);
        let wrapped = move |req: Arc<Request>| {
            let f = Arc::clone(&f);
            Box::pin(async move {
                // `req` is owned by this future (Arc), so borrowing it is safe across `.await`.
                (&*f)(req.as_ref()).await
            })
        };
        Handler(Arc::new(wrapped))
    }
}

// Conversion for a sync handler: for<'a> Fn(&'a Request) -> Response
impl<F> From<F> for Handler
where
    F: for<'a> Fn(&'a Request) -> Response + Send + Sync + 'static,
{
    fn from(f: F) -> Self {
        let f = Arc::new(f);
        let wrapped = move |req: Arc<Request>| {
            let f = Arc::clone(&f);
            Box::pin(async move { (&*f)(req.as_ref()) })
        };
        Handler(Arc::new(wrapped))
    }
}

// --- Simplified server ---

pub struct Server {
    routes: HashMap<String, Handler>,
}

impl Server {
    pub fn new() -> Self {
        Self {
            routes: HashMap::new(),
        }
    }

    pub fn add_route<F>(&mut self, path: &str, f: F)
    where
        Handler: From<F>,
    {
        self.routes.insert(path.to_string(), Handler::from(f));
    }

    pub async fn handle(&self, path: &str, req: Request) -> Response {
        let Some(handler) = self.routes.get(path) else {
            return Response {
                body: format!("404: {path}"),
            };
        };

        handler.call(Arc::new(req)).await
    }
}

// --- User code (example) ---

fn sync_handler(req: &Request) -> Response {
    Response {
        body: format!("sync: got path={}", req.path),
    }
}

async fn async_handler(req: &Request) -> Response {
    // (pretend to do async work)
    Response {
        body: format!("async: got path={}", req.path),
    }
}

fn main() {
    let mut server = Server::new();

    // Same API call works for both sync and async handlers.
    server.add_route("/sync", sync_handler);
    server.add_route("/async", async_handler);

    let r1 = futures::executor::block_on(server.handle(
        "/sync",
        Request {
            path: "/sync".to_string(),
        },
    ));
    println!("{r1:?}");

    let r2 = futures::executor::block_on(server.handle(
        "/async",
        Request {
            path: "/async".to_string(),
        },
    ));
    println!("{r2:?}");
}
"
}
