  "main.rs": "//! This single source file is compiled twice:
//! - as a proc-macro crate (cfg(proc_macro) = true)
//! - as a normal binary (cfg(proc_macro) = false)

// ------------------------------
// Proc-macro implementation
// ------------------------------

#[cfg(proc_macro)]
extern crate proc_macro;

#[cfg(proc_macro)]
mod notion_derive {
    use proc_macro::TokenStream;
    use quote::quote;
    use syn::{
        parse_macro_input, spanned::Spanned, Data, DeriveInput, Fields, GenericArgument, LitStr,
        PathArguments, Type,
    };

    #[proc_macro_derive(NotionProperties, attributes(notion_property))]
    pub fn notion_properties_derive(input: TokenStream) -> TokenStream {
        let input = parse_macro_input!(input as DeriveInput);
        let struct_ident = input.ident;

        let Data::Struct(data_struct) = input.data else {
            return syn::Error::new(input.span(), "NotionProperties can only be derived for structs")
                .to_compile_error()
                .into();
        };

        let Fields::Named(fields_named) = data_struct.fields else {
            return syn::Error::new(
                data_struct.fields.span(),
                "NotionProperties requires a struct with named fields",
            )
            .to_compile_error()
            .into();
        };

        let mut field_inserts = Vec::new();

        for field in fields_named.named {
            let Some(field_ident) = field.ident else {
                continue;
            };

            // Find #[notion_property(type = "...", name = "...")]
            let mut prop_type: Option<String> = None;
            let mut prop_name: Option<String> = None;

            for attr in &field.attrs {
                if !attr.path().is_ident("notion_property") {
                    continue;
                }

                let parse_result = attr.parse_nested_meta(|meta| {
                    if meta.path.is_ident("type") {
                        let lit: LitStr = meta.value()?.parse()?;
                        prop_type = Some(lit.value());
                        Ok(())
                    } else if meta.path.is_ident("name") {
                        let lit: LitStr = meta.value()?.parse()?;
                        prop_name = Some(lit.value());
                        Ok(())
                    } else {
                        Err(meta.error("expected `type = \"...\"` or `name = \"...\"`") )
                    }
                });

                if let Err(e) = parse_result {
                    return e.to_compile_error().into();
                }
            }

            let Some(prop_type) = prop_type else {
                // No attribute: skip the field.
                continue;
            };
            let Some(prop_name) = prop_name else {
                return syn::Error::new(
                    field.span(),
                    "missing `name = \"...\"` in #[notion_property(...)]",
                )
                .to_compile_error()
                .into();
            };

            let prop_name_lit = LitStr::new(&prop_name, field.span());

            let (is_option, _inner_ty) = option_inner_type(&field.ty);
            let prop_type_norm = prop_type.to_lowercase();

            let insert_tokens = match prop_type_norm.as_str() {
                "title" => {
                    if is_option {
                        quote! {
                            if let Some(ref v) = self.#field_ident {
                                map.insert(
                                    #prop_name_lit.to_string(),
                                    crate::PropertyValue::Title(crate::title_from_string(v.clone())),
                                );
                            }
                        }
                    } else {
                        quote! {
                            map.insert(
                                #prop_name_lit.to_string(),
                                crate::PropertyValue::Title(crate::title_from_string(self.#field_ident.clone())),
                            );
                        }
                    }
                }
                "url" => {
                    if is_option {
                        quote! {
                            if let Some(ref v) = self.#field_ident {
                                map.insert(
                                    #prop_name_lit.to_string(),
                                    crate::PropertyValue::Url(v.clone()),
                                );
                            }
                        }
                    } else {
                        quote! {
                            map.insert(
                                #prop_name_lit.to_string(),
                                crate::PropertyValue::Url(self.#field_ident.clone()),
                            );
                        }
                    }
                }
                "multiselect" | "multi_select" | "multi-select" => {
                    if is_option {
                        quote! {
                            if let Some(ref v) = self.#field_ident {
                                map.insert(
                                    #prop_name_lit.to_string(),
                                    crate::PropertyValue::MultiSelect(crate::multi_select_from_iter(v.iter())),
                                );
                            }
                        }
                    } else {
                        quote! {
                            map.insert(
                                #prop_name_lit.to_string(),
                                crate::PropertyValue::MultiSelect(crate::multi_select_from_iter(self.#field_ident.iter())),
                            );
                        }
                    }
                }
                other => {
                    return syn::Error::new(
                        field.span(),
                        format!("unsupported notion property type `{}`", other),
                    )
                    .to_compile_error()
                    .into();
                }
            };

            field_inserts.push(insert_tokens);
        }

        let expanded = quote! {
            impl crate::ToNotionProperties for #struct_ident {
                fn to_notion_properties(&self) -> ::std::collections::HashMap<String, crate::PropertyValue> {
                    let mut map = ::std::collections::HashMap::new();
                    #(#field_inserts)*
                    map
                }
            }
        };

        expanded.into()
    }

    fn option_inner_type(ty: &Type) -> (bool, Option<&Type>) {
        let Type::Path(type_path) = ty else {
            return (false, None);
        };
        let Some(seg) = type_path.path.segments.last() else {
            return (false, None);
        };
        if seg.ident != "Option" {
            return (false, None);
        }
        let PathArguments::AngleBracketed(args) = &seg.arguments else {
            return (true, None);
        };
        let Some(GenericArgument::Type(inner)) = args.args.first() else {
            return (true, None);
        };
        (true, Some(inner))
    }
}

// Re-export the derive macro from the proc-macro build.
#[cfg(proc_macro)]
pub use notion_derive::*;

// ------------------------------
// Runtime / demo binary
// ------------------------------

#[cfg(not(proc_macro))]
mod runtime {
    use serde::{Deserialize, Serialize};
    use serde_json::Value;
    use std::collections::HashMap;

    // Import the derive macro from the proc-macro library crate (same package name).
