        #[serde(rename = "title")]
        Title(Vec<RichTextObject>),

        #[serde(rename = "url")]
        Url(String),

        #[serde(rename = "multi_select")]
        MultiSelect(Vec<SelectObject>),
    }

    // ---- Helpers the macro expansion will call ----

    pub fn title_from_string(s: String) -> Vec<RichTextObject> {
        vec![RichTextObject {
            annotations: None,
            data_type: Some(RichTextType::Text),
            equation: None,
            mention: None,
            plain_text: None,
            href: None,
            text: TextObject { content: s, link: None },
        }]
    }

    pub trait ToSelectName {
