use rustyline::error::ReadlineError;
use rustyline::history::DefaultHistory;
use rustyline::keymap::{ConditionalEventHandler, Event, EventContext, EventHandler, KeyEvent, Modifiers, RepeatCount};
use rustyline::{Cmd, Editor, Movement};

/// Delete any whitespace immediately before the cursor, then insert a character
/// (e.g. '.' or ',') and leave the cursor *after* the inserted character.
///
/// This uses `Cmd::Macro(Vec<Cmd>)` to combine multiple editing actions into one.
struct DeleteWsThenInsert {
    insert: String,
}

impl DeleteWsThenInsert {
    fn new(ch: char) -> Self {
        Self {
            insert: ch.to_string(),
        }
    }
}

impl ConditionalEventHandler for DeleteWsThenInsert {
    fn handle(
        &self,
        _event: &Event,
        count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();

        // Count trailing whitespace immediately before the cursor.
        // `pos` is a byte index in `line` (rustyline keeps cursor at UTF-8 boundaries).
        let ws = line[..pos]
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        let mut cmds = Vec::with_capacity(2);

        if ws > 0 {
            cmds.push(Cmd::Kill(Movement::BackwardChar(ws as RepeatCount)));
        }

        // Make sure we always insert the character (even if there was no whitespace).
        let n = if count == 0 { 1 } else { count };
        cmds.push(Cmd::Insert(n, self.insert.clone()));

        Some(Cmd::Macro(cmds))
    }
}

fn bind_delete_ws_then_insert(editor: &mut Editor<(), DefaultHistory>, key: char) {
    let event = KeyEvent::new(key, Modifiers::NONE);
    let handler = DeleteWsThenInsert::new(key);
    editor.bind_sequence(event, EventHandler::Conditional(Box::new(handler)));
}

fn main() {
    let mut rl = Editor::<(), DefaultHistory>::new().expect("create editor");

    // Bind '.' and ',' so they remove whitespace immediately before the cursor.
    bind_delete_ws_then_insert(&mut rl, '.');
    bind_delete_ws_then_insert(&mut rl, ',');

    loop {
        match rl.readline("zql> ") {
            Ok(line) => {
                let trimmed = line.trim();
                if trimmed.eq_ignore_ascii_case("exit") || trimmed.eq_ignore_ascii_case("quit") {
