    let a_obj: A = serde_json::from_value(resolved)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}

fn ensure_example_files_exist() -> Result<(), Box<dyn Error>> {
    let a_json = r#"{
  "p_list": [
    "./a/b/c/def",
    "./g/h/i/jkl"
  ]
}"#;

    let b_json = r#"{
  "path_list": {
    "$ref": "./a.json#/p_list"
  }
}"#;

    if !Path::new("a.json").exists() {
        fs::write("a.json", a_json)?;
    }
    if !Path::new("b.json").exists() {
        fs::write("b.json", b_json)?;
    }
    Ok(())
}

/// Recursively resolves JSON objects of the form `{ "$ref": "./file.json#/pointer" }`.
///
/// - `current_file` is the path of the JSON file that contained `value`.
///   It is used to resolve relative `$ref` file paths.
fn resolve_refs(value: Value, current_file: &Path) -> Result<Value, Box<dyn Error>> {
    match value {
        Value::Array(arr) => {
            let mut out = Vec::with_capacity(arr.len());
            for v in arr {
                out.push(resolve_refs(v, current_file)?);
            }
            Ok(Value::Array(out))
        }
        Value::Object(obj) => {
            // If this object is exactly a $ref object, resolve it.
            if obj.len() == 1 {
                if let Some(Value::String(r)) = obj.get("$ref") {
                    return resolve_single_ref(r, current_file);
                }
            }

            // Otherwise recurse into the object values.
            let mut out: BTreeMap<String, Value> = BTreeMap::new();
            for (k, v) in obj {
                out.insert(k, resolve_refs(v, current_file)?);
            }
            Ok(Value::Object(out.into_iter().collect()))
        }
        other => Ok(other),
    }
}

